const xml = $input.first()?.json?.data || '';
const config = $('1. Set Master Workspace Credentials').first()?.json || {};
const text = (v = '') => String(v).replace(/<!\[CDATA\[([\s\S]*?)\]\]>/g, '$1').replace(/<[^>]*>/g, '').trim();
const pick = (block, tag) => text((block.match(new RegExp(`<${tag}[^>]*>([\s\S]*?)<\/${tag}>`, 'i')) || [])[1] || '');
const matches = [...xml.matchAll(/<item>([\s\S]*?)<\/item>/gi)].slice(0, 5);
const items = matches.map((m) => {
  const item = m[1]; const title = pick(item, 'title'); const pub = pick(item, 'pubDate'); const traffic = pick(item, 'ht:approx_traffic');
  if (!title) return null;
  return {
    json: {
      workspaceId: config.workspaceId,
      title: `Google Trends: ${title}`,
      sourceUrl: `https://trends.google.com/trends/explore?q=${encodeURIComponent(title)}`,
      publishedAt: pub ? new Date(pub).toISOString() : new Date().toISOString(),
      sourceName: 'Google Trends RSS',
      sourceType: 'trend',
      content: `Trending topic on Google: ${title}. Approximate search traffic: ${traffic || 'Not specified'}. Grounded trend signal collected automatically.`,
      automationSecret: config.automationSecret
    }
  };
}).filter(Boolean);
return items.length ? items : [];

const config = $('1. Set Master Workspace Credentials').first()?.json || {};
const rawItems = $input.first()?.json?.items || [];
const items = rawItems.map((item) => {
  const s = item.snippet || {};
  const vId = item.id?.videoId || '';
  const title = s.title || '';
  if (!title || !vId) return null;
  return {
    json: {
      workspaceId: config.workspaceId,
      title: `YouTube Video: ${title}`,
      sourceUrl: `https://www.youtube.com/watch?v=${vId}`,
      publishedAt: s.publishedAt || new Date().toISOString(),
      sourceName: 'YouTube Data API',
      sourceType: 'media',
      content: `YouTube video content for industry '${config.researchQuery}'. Video title: ${title}. Channel: ${s.channelTitle || 'Unknown'}. Description: ${s.description || 'N/A'}`,
      automationSecret: config.automationSecret
    }
  };
}).filter(Boolean);
return items.length ? items : [];

const config = $('1. Set Master Workspace Credentials').first()?.json || {};
const articles = $input.first()?.json?.articles || [];
const items = articles.slice(0, 5).map((art) => {
  if (!art.title || !art.url || !art.url.startsWith('http')) return null;
  return {
    json: {
      workspaceId: config.workspaceId,
      title: `GDELT News: ${art.title}`,
      sourceUrl: art.url,
      publishedAt: art.seendate ? `${art.seendate.slice(0,4)}-${art.seendate.slice(4,6)}-${art.seendate.slice(6,8)}T00:00:00Z` : new Date().toISOString(),
      sourceName: 'GDELT DOC API',
      sourceType: 'report',
      content: `Industry news article for '${config.researchQuery}'. Title: ${art.title}. Domain: ${art.domain || 'Unknown'}. Public URL: ${art.url}`,
      automationSecret: config.automationSecret
    }
  };
}).filter(Boolean);
return items.length ? items : [];

const config = $input.first()?.json || {};
const cleanQuery = (config.researchQuery || 'Clothing').replace(/[^a-zA-Z0-9]/g, '');
const wikipediaTitle = cleanQuery || 'Clothing';
const end = new Date(); end.setUTCDate(end.getUTCDate() - 1);
const start = new Date(end); start.setUTCDate(start.getUTCDate() - 29);
const fmt = (d) => d.toISOString().slice(0, 10).replaceAll('-', '') + '00';
return [{ json: { ...config, wikiArticle: wikipediaTitle, startFmt: fmt(start), endFmt: fmt(end) } }];

const config = $('1. Set Master Workspace Credentials').first()?.json || {};
const rawItems = $input.first()?.json?.items || [];
if (!rawItems.length) return [];
const views = rawItems.map((i) => Number(i.views || 0));
const avg = views.reduce((a, b) => a + b, 0) / views.length;
return [{
  json: {
    workspaceId: config.workspaceId,
    title: `Wikimedia Attention: ${config.researchQuery || 'Clothing'}`,
    sourceUrl: `https://en.wikipedia.org/wiki/${encodeURIComponent(config.researchQuery || 'Clothing')}`,
    publishedAt: new Date().toISOString(),
    sourceName: 'Wikimedia Pageviews API',
    sourceType: 'report',
    content: `Wikimedia pageview attention signal for Wikipedia article '${config.researchQuery || 'Clothing'}'. 30-day average daily pageviews: ${avg.toFixed(0)}.`,
    automationSecret: config.automationSecret
  }
}];
